class EventStore(ABC):
    @abstractmethod
    async def append(self, stream_id: str, events: List[Event], expected_version: int) -> None:
        """Append events with optimistic concurrency check."""
        pass

    @abstractmethod
    async def read_stream(self, stream_id: str, from_version: int = 0) -> List[Event]:
        """Read all events from a stream starting at from_version."""
        pass

    @abstractmethod
    async def read_all(self, from_position: int = 0, batch_size: int = 100) -> List[Event]:
        """Read all events across all streams (for projection rebuilding)."""
        pass

CREATE TABLE events (
    id           BIGSERIAL PRIMARY KEY,
    event_id     UUID        NOT NULL UNIQUE,
    stream_id    VARCHAR(255) NOT NULL,
    version      INTEGER     NOT NULL,
    event_type   VARCHAR(255) NOT NULL,
    event_data   JSONB       NOT NULL,
    metadata     JSONB       NOT NULL DEFAULT '{}',
    occurred_at  TIMESTAMP   NOT NULL,
    created_at   TIMESTAMP   NOT NULL DEFAULT NOW(),

    CONSTRAINT events_stream_version_unique UNIQUE (stream_id, version)
);

CREATE INDEX events_stream_id_idx  ON events(stream_id);
CREATE INDEX events_event_type_idx ON events(event_type);
CREATE INDEX events_occurred_at_idx ON events(occurred_at);

CREATE TABLE snapshots (
    stream_id   VARCHAR(255) PRIMARY KEY,
    version     INTEGER  NOT NULL,
    state       JSONB    NOT NULL,
    created_at  TIMESTAMP NOT NULL
);

class EventBus:
    def __init__(self):
        self._handlers: Dict[str, List[Callable]] = {}

    def subscribe(self, event_type: str, handler: Callable) -> None:
        self._handlers.setdefault(event_type, []).append(handler)

    async def publish(self, event) -> None:
        for handler in self._handlers.get(type(event).__name__, []):
            await handler(event)

# Wiring
event_bus = EventBus()
projection = OrderDetailsProjection(session)
event_bus.subscribe("OrderCreated", projection.handle_order_created)
event_bus.subscribe("OrderPlaced",  projection.handle_order_placed)
